// Rate limiter : max 3 estimations par email par heure
const WINDOW = 60 * 60 * 1000;
const MAX_REQUESTS = 3;
const email = $('Webhook MERINO').first().json.body.email;
const ip = $('Webhook MERINO').first().json.headers['x-real-ip'] ?? $('Webhook MERINO').first().json.headers['x-forwarded-for'] ?? 'unknown';
const now = Date.now();

const staticData = $getWorkflowStaticData('global');
if (!staticData.rateLimits) staticData.rateLimits = {};

// Clé combinée email + IP
const key = `${email}__${ip}`;

// Nettoyer les entrées expirées
for (const k of Object.keys(staticData.rateLimits)) {
  staticData.rateLimits[k] = staticData.rateLimits[k].filter(t => now - t < WINDOW);
  if (staticData.rateLimits[k].length === 0) delete staticData.rateLimits[k];
}

const hits = staticData.rateLimits[key] ?? [];
const blocked = hits.length >= MAX_REQUESTS;

if (!blocked) {
  hits.push(now);
  staticData.rateLimits[key] = hits;
}

return [{ json: { blocked, remaining: MAX_REQUESTS - hits.length, ...$input.first().json } }];

// Parser la réponse de Claude + récupérer les données du lead
const raw = $input.first().json;
const claudeRaw = raw.text ?? raw.content?.[0]?.text ?? JSON.stringify(raw);
const lead = $('Webhook MERINO').first().json.body;

let estimation;
try {
  const clean = claudeRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  estimation = JSON.parse(clean);
} catch (e) {
  estimation = { prixBas: 0, prixHaut: 0, commentaire: 'Estimation à affiner avec nos experts.' };
}

const formatPrice = (p) => new Intl.NumberFormat('fr-FR', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 }).format(p);

return [{
  json: {
    // Estimation Claude
    prixBas: estimation.prixBas,
    prixHaut: estimation.prixHaut,
    prixBasFmt: formatPrice(estimation.prixBas),
    prixHautFmt: formatPrice(estimation.prixHaut),
    commentaire: estimation.commentaire,
    // Lead
    prenom: lead.prenom,
    nom: lead.nom,
    email: lead.email,
    telephone: lead.telephone,
    type: lead.type,
    adresse: lead.adresse,
    surface: lead.surface,
    chambres: lead.chambres,
    anneeConstruction: lead.anneeConstruction,
    etatInterieur: lead.etatInterieur,
    etatCommuns: lead.etatCommuns,
    surfaceBalcon: lead.surfaceBalcon ?? 0,
    surfaceTerrasse: lead.surfaceTerrasse ?? 0,
    surfaceJardin: lead.surfaceJardin ?? 0,
    statInterieur: lead.statInterieur ?? 0,
    statExterieur: lead.statExterieur ?? 0,
    agent: lead.agent ?? 'jordane',
    agentNom: (lead.agent === 'louis') ? 'Louis PETITCOLIN' : 'Jordane MOREL',
    agentEmail: (lead.agent === 'louis') ? 'louis@agencemerino.com' : 'jordane@agencemerino.com',
    agentTel: (lead.agent === 'louis') ? '+33 7 59 59 92 97' : '+33 6 95 06 73 20',
    soumisLe: new Date().toLocaleString('fr-FR', { timeZone: 'Europe/Paris' })
  }
}];
